import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.ApplicationContext;
import org.springframework.stereotype.Component;
import org.springframework.stereotype.Service;

import javax.annotation.Resource;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

/**
 * Spring 静态内部类注入失效的解决方案示例
 */
@Component
public class SpringStaticClassInjectionSolution {

    // ==================== 方案1: 通过构造函数传递依赖（推荐） ====================

    @Resource
    private YourService yourService;

    private ExecutorService executorService = Executors.newFixedThreadPool(10);

    /**
     * 方案1：将依赖通过构造函数传递给 Runnable 任务
     * 优点：简单直接，符合依赖注入原则
     * 适用场景：依赖较少，任务相对独立
     */
    public void solution1_ConstructorInjection() {
        // 将 Service 通过构造函数传递
        ProcessDataBatchTask task = new ProcessDataBatchTask(yourService);
        executorService.submit(task);
    }

    // 去掉 static 关键字，或者通过构造函数注入依赖
    private static class ProcessDataBatchTask implements Runnable {
        private final YourService service;  // 通过构造函数注入

        public ProcessDataBatchTask(YourService service) {
            this.service = service;
        }

        @Override
        public void run() {
            // 现在可以正常使用 service 了
            service.processData();
        }
    }


    // ==================== 方案2: 改为非静态内部类 ====================

    /**
     * 方案2：将静态内部类改为非静态内部类
     * 优点：可以直接访问外部类的成员变量
     * 缺点：内部类持有外部类引用，可能影响 GC
     */
    public void solution2_NonStaticInnerClass() {
        NonStaticBatchTask task = new NonStaticBatchTask();
        executorService.submit(task);
    }

    // 非静态内部类，可以直接访问外部类的 yourService
    private class NonStaticBatchTask implements Runnable {
        @Override
        public void run() {
            // 直接使用外部类的 yourService
            yourService.processData();
        }
    }


    // ==================== 方案3: 使用 ApplicationContext 手动获取 Bean（不推荐） ====================

    @Autowired
    private ApplicationContext applicationContext;

    /**
     * 方案3：通过 ApplicationContext 手动获取 Bean
     * 缺点：违反了依赖注入原则，增加了与 Spring 的耦合
     * 仅在无法使用前两种方案时使用
     */
    public void solution3_ApplicationContext() {
        ApplicationContextBatchTask task = new ApplicationContextBatchTask(applicationContext);
        executorService.submit(task);
    }

    private static class ApplicationContextBatchTask implements Runnable {
        private final ApplicationContext context;

        public ApplicationContextBatchTask(ApplicationContext context) {
            this.context = context;
        }

        @Override
        public void run() {
            // 手动从容器获取 Bean
            YourService service = context.getBean(YourService.class);
            service.processData();
        }
    }


    // ==================== 方案4: 使用 SpringContextHolder 工具类 ====================

    /**
     * 方案4：使用静态工具类获取 Bean
     * 优点：不需要传递 ApplicationContext
     * 缺点：仍然违反依赖注入原则
     */
    public void solution4_SpringContextHolder() {
        SpringContextHolderBatchTask task = new SpringContextHolderBatchTask();
        executorService.submit(task);
    }

    private static class SpringContextHolderBatchTask implements Runnable {
        @Override
        public void run() {
            // 通过工具类获取 Bean
            YourService service = SpringContextHolder.getBean(YourService.class);
            service.processData();
        }
    }


    // ==================== 方案5: 将 Runnable 本身注册为 Prototype Bean ====================

    /**
     * 方案5：将任务类本身注册为 Spring Bean（Prototype 作用域）
     * 优点：完全由 Spring 管理，支持所有 Spring 特性
     * 适用场景：任务类较复杂，需要多个依赖注入
     */
    public void solution5_PrototypeBean() {
        // 从 Spring 容器获取 Bean
        PrototypeBatchTask task = applicationContext.getBean(PrototypeBatchTask.class);
        executorService.submit(task);
    }
}


// ==================== 辅助类 ====================

/**
 * 示例 Service
 */
@Service
class YourService {
    public void processData() {
        System.out.println("Processing data...");
    }
}


/**
 * Spring 上下文工具类（需要单独创建）
 */
@Component
class SpringContextHolder implements org.springframework.context.ApplicationContextAware {

    private static ApplicationContext applicationContext;

    @Override
    public void setApplicationContext(ApplicationContext context) {
        applicationContext = context;
    }

    public static <T> T getBean(Class<T> clazz) {
        if (applicationContext == null) {
            throw new IllegalStateException("ApplicationContext is not initialized");
        }
        return applicationContext.getBean(clazz);
    }

    public static Object getBean(String beanName) {
        if (applicationContext == null) {
            throw new IllegalStateException("ApplicationContext is not initialized");
        }
        return applicationContext.getBean(beanName);
    }
}


/**
 * Prototype 作用域的任务 Bean
 */
@Component
@org.springframework.context.annotation.Scope("prototype")
class PrototypeBatchTask implements Runnable {

    @Resource
    private YourService yourService;  // 这里可以正常注入

    @Override
    public void run() {
        // 可以直接使用注入的 Service
        yourService.processData();
    }
}
"}

{"file_path": "/home/ubuntu/single/workspace_simple/task_f8350b0976f7caf895ba5c27cf454fba/SOLUTION_GUIDE.md", "content": "# Spring 静态内部类注入失效问题解决指南

## 问题描述

在 `static class ProcessDataBatchTask implements Runnable` 中使用 `@Resource` 注入 Service 时显示为 `null`。

## 根本原因

### 1. 静态内部类不会被 Spring 容器管理
- 静态内部类无法自动注册为 Spring Bean
- `@Resource`、`@Autowired` 等注解只对 Spring 容器管理的 Bean 有效

### 2. 直接 new 创建实例
```java
// 错误示例
ProcessDataBatchTask task = new ProcessDataBatchTask();
executorService.submit(task);  // Service 字段为 null
```

### 3. Spring 无法对静态成员进行注入
即使类被 Spring 管理，静态字段也无法注入：
```java
// 这样也不行
private static class ProcessDataBatchTask implements Runnable {
    @Resource
    private static YourService yourService;  // 永远是 null
}
```

---

## 解决方案对比

| 方案 | 优点 | 缺点 | 推荐度 |
|------|------|------|--------|
| 1. 构造函数传递 | 简单直接，符合依赖注入原则 | 依赖多时构造函数参数多 | ⭐⭐⭐⭐⭐ |
| 2. 非静态内部类 | 可直接访问外部类成员 | 持有外部类引用，可能影响 GC | ⭐⭐⭐⭐ |
| 3. ApplicationContext | 灵活 | 违反 DI 原则，耦合度高 | ⭐⭐ |
| 4. SpringContextHolder | 使用方便 | 同上，且引入全局状态 | ⭐⭐ |
| 5. Prototype Bean | 完全由 Spring 管理 | 获取 Bean 需要依赖容器 | ⭐⭐⭐⭐ |

---

## 推荐方案：构造函数传递（方案1）

### 原始代码（错误示例）

```java
@Component
public class DataProcessor {

    @Resource
    private YourService yourService;

    public void processAsync() {
        // 创建任务
        ProcessDataBatchTask task = new ProcessDataBatchTask();
        executorService.submit(task);
    }

    // ❌ 问题代码
    private static class ProcessDataBatchTask implements Runnable {
        @Resource
        private YourService yourService;  // 这里永远是 null

        @Override
        public void run() {
            yourService.processData();  // NullPointerException!
        }
    }
}
```

### 修复后的代码（推荐）

```java
@Component
public class DataProcessor {

    @Resource
    private YourService yourService;

    public void processAsync() {
        // ✅ 通过构造函数传递依赖
        ProcessDataBatchTask task = new ProcessDataBatchTask(yourService);
        executorService.submit(task);
    }

    // ✅ 修复：通过构造函数注入
    private static class ProcessDataBatchTask implements Runnable {
        private final YourService yourService;  // final 保证不可变

        public ProcessDataBatchTask(YourService yourService) {
            this.yourService = yourService;
        }

        @Override
        public void run() {
            yourService.processData();  // 正常工作
        }
    }
}
```

---

## 方案2：改为非静态内部类

```java
@Component
public class DataProcessor {

    @Resource
    private YourService yourService;

    public void processAsync() {
        // 创建非静态内部类实例
        ProcessDataBatchTask task = new ProcessDataBatchTask();
        executorService.submit(task);
    }

    // ✅ 去掉 static 关键字
    private class ProcessDataBatchTask implements Runnable {
        @Override
        public void run() {
            // 可以直接访问外部类的 yourService
            yourService.processData();
        }
    }
}
```

**注意事项**：
- 非静态内部类会隐式持有外部类的引用
- 如果任务生命周期较长，可能导致外部类无法被 GC 回收
- 如果外部类是单例 Bean，通常没有问题

---

## 方案3：SpringContextHolder 工具类

### 第一步：创建工具类

```java
@Component
public class SpringContextHolder implements ApplicationContextAware {

    private static ApplicationContext applicationContext;

    @Override
    public void setApplicationContext(ApplicationContext context) {
        applicationContext = context;
    }

    public static <T> T getBean(Class<T> clazz) {
        if (applicationContext == null) {
            throw new IllegalStateException("ApplicationContext not initialized");
        }
        return applicationContext.getBean(clazz);
    }

    public static Object getBean(String beanName) {
        return applicationContext.getBean(beanName);
    }
}
```

### 第二步：在任务中使用

```java
private static class ProcessDataBatchTask implements Runnable {
    @Override
    public void run() {
        // 从容器获取 Bean
        YourService service = SpringContextHolder.getBean(YourService.class);
        service.processData();
    }
}
```

---

## 方案4：Prototype 作用域 Bean

### 将任务类注册为 Bean

```java
@Component
@Scope("prototype")  // 每次获取都创建新实例
public class ProcessDataBatchTask implements Runnable {

    @Resource
    private YourService yourService;  // ✅ 可以正常注入

    @Resource
    private AnotherService anotherService;  // 支持多个依赖

    @Override
    public void run() {
        yourService.processData();
        anotherService.doSomething();
    }
}
```

### 使用时从容器获取

```java
@Component
public class DataProcessor {

    @Autowired
    private ApplicationContext applicationContext;

    public void processAsync() {
        // 从容器获取 prototype Bean
        ProcessDataBatchTask task = applicationContext.getBean(ProcessDataBatchTask.class);
        executorService.submit(task);
    }
}
```

---

## 实际案例：多依赖场景

如果你的任务需要注入多个 Service：

```java
@Component
public class ComplexDataProcessor {

    @Resource
    private ServiceA serviceA;

    @Resource
    private ServiceB serviceB;

    @Resource
    private ServiceC serviceC;

    public void processAsync() {
        // 方案1：构造函数传递（推荐）
        ProcessTask task = new ProcessTask(serviceA, serviceB, serviceC);
        executorService.submit(task);
    }

    private static class ProcessTask implements Runnable {
        private final ServiceA serviceA;
        private final ServiceB serviceB;
        private final ServiceC serviceC;

        public ProcessTask(ServiceA serviceA, ServiceB serviceB, ServiceC serviceC) {
            this.serviceA = serviceA;
            this.serviceB = serviceB;
            this.serviceC = serviceC;
        }

        @Override
        public void run() {
            serviceA.process();
            serviceB.handle();
            serviceC.execute();
        }
    }
}
```

或者使用 Prototype Bean 方案：

```java
@Component
@Scope("prototype")
public class ComplexProcessTask implements Runnable {

    @Resource
    private ServiceA serviceA;

    @Resource
    private ServiceB serviceB;

    @Resource
    private ServiceC serviceC;

    @Override
    public void run() {
        serviceA.process();
        serviceB.handle();
        serviceC.execute();
    }
}
```

---

## 最佳实践建议

### ✅ 推荐做法

1. **优先使用构造函数传递**：简单、明确、可测试
2. **依赖较多时使用 Prototype Bean**：充分利用 Spring 的依赖注入
3. **明确标记 final**：构造函数注入的字段标记为 `final`，保证不可变性

### ❌ 避免做法

1. **避免在静态字段上使用 `@Resource`/`@Autowired`**：永远不会生效
2. **避免过度使用 ApplicationContext**：违反依赖注入原则
3. **避免将单例外部类的非静态内部类作为长期任务**：可能导致内存泄漏

---

## 调试技巧

### 如何确认注入是否成功

```java
@Override
public void run() {
    if (yourService == null) {
        System.err.println("❌ Service is null - injection failed!");
        return;
    }
    System.out.println("✅ Service injected successfully: " + yourService.getClass().getName());
    yourService.processData();
}
```

### 检查 Bean 是否被 Spring 管理

```java
@Component
public class BeanChecker {

    @Autowired
    private ApplicationContext context;

    public void checkBean() {
        try {
            YourService service = context.getBean(YourService.class);
            System.out.println("✅ Bean found: " + service);
        } catch (NoSuchBeanDefinitionException e) {
            System.err.println("❌ Bean not found in Spring context!");
        }
    }
}
```

---

## 常见问题 FAQ

### Q1: 为什么静态内部类不能使用 @Resource？
**A**: 静态内部类不会被 Spring 扫描和管理，`@Resource` 注解只对 Spring Bean 生效。

### Q2: 能否在静态字段上使用 @Autowired？
**A**: 不能。Spring 无法对静态字段进行依赖注入，即使在 Bean 类中也不行。

### Q3: 非静态内部类会导致内存泄漏吗？
**A**: 可能。如果任务生命周期很长，会持有外部类引用，导致外部类无法被 GC。对于短期任务，通常没问题。

### Q4: Prototype Bean 每次都创建新实例吗？
**A**: 是的。`@Scope("prototype")` 确保每次调用 `getBean()` 都返回新实例。

### Q5: 哪种方案性能最好？
**A**: 构造函数传递和非静态内部类性能最好，ApplicationContext 方式会有额外的 Bean 查找开销。

---

## 总结

| 场景 | 推荐方案 |
|------|---------|
| 依赖少，任务简单 | 构造函数传递（方案1） |
| 需要访问外部类多个成员 | 非静态内部类（方案2） |
| 依赖多，任务复杂 | Prototype Bean（方案5） |
| 临时解决方案 | SpringContextHolder（方案4） |

**核心原则**：静态类无法被 Spring 注入，解决办法是将依赖显式传递进去，或者改为非静态类/Bean。
"}

