using System.Collections.Generic;
using System.IO;
using System.Reflection;

/// <summary>
/// 处理 ReflectionOnly 加载场景下的程序集依赖解析
/// </summary>
public class ReflectionOnlyLoader
{
    private readonly List<string> _probingPaths;
    private readonly Dictionary<string, Assembly> _loadedAssemblies;

    public ReflectionOnlyLoader()
    {
        _probingPaths = new List<string>();
        _loadedAssemblies = new Dictionary<string, Assembly>(StringComparer.OrdinalIgnoreCase);

        // 订阅 ReflectionOnlyAssemblyResolve 事件
        AppDomain.CurrentDomain.ReflectionOnlyAssemblyResolve += OnReflectionOnlyAssemblyResolve;
    }

    /// <summary>
    /// 添加程序集搜索路径
    /// </summary>
    public void AddProbingPath(string path)
    {
        if (Directory.Exists(path) && !_probingPaths.Contains(path))
        {
            _probingPaths.Add(path);
        }
    }

    /// <summary>
    /// 预加载指定的程序集及其依赖项
    /// </summary>
    public Assembly PreloadAssembly(string assemblyPath)
    {
        if (!File.Exists(assemblyPath))
        {
            throw new FileNotFoundException($"Assembly not found: {assemblyPath}");
        }

        try
        {
            // 使用 ReflectionOnlyLoadFrom 加载主程序集
            Assembly assembly = Assembly.ReflectionOnlyLoadFrom(assemblyPath);

            // 缓存已加载的程序集
            string assemblyName = assembly.FullName;
            if (!_loadedAssemblies.ContainsKey(assemblyName))
            {
                _loadedAssemblies[assemblyName] = assembly;
            }

            // 递归预加载所有引用的程序集
            PreloadReferencedAssemblies(assembly);

            return assembly;
        }
        catch (Exception ex)
        {
            throw new InvalidOperationException($"Failed to preload assembly: {assemblyPath}", ex);
        }
    }

    /// <summary>
    /// 预加载指定程序集的所有引用程序集
    /// </summary>
    private void PreloadReferencedAssemblies(Assembly assembly)
    {
        foreach (AssemblyName referencedAssembly in assembly.GetReferencedAssemblies())
        {
            try
            {
                // 如果已经加载过,跳过
                if (_loadedAssemblies.ContainsKey(referencedAssembly.FullName))
                {
                    continue;
                }

                // 尝试加载引用的程序集
                Assembly loadedAssembly = LoadReferencedAssembly(referencedAssembly);

                if (loadedAssembly != null)
                {
                    _loadedAssemblies[referencedAssembly.FullName] = loadedAssembly;

                    // 递归加载该程序集的依赖项
                    PreloadReferencedAssemblies(loadedAssembly);
                }
            }
            catch (Exception ex)
            {
                // 记录警告但继续处理其他程序集
                Console.WriteLine($"Warning: Could not preload referenced assembly '{referencedAssembly.FullName}': {ex.Message}");
            }
        }
    }

    /// <summary>
    /// 加载引用的程序集
    /// </summary>
    private Assembly LoadReferencedAssembly(AssemblyName assemblyName)
    {
        // 1. 尝试从 GAC 加载
        try
        {
            return Assembly.ReflectionOnlyLoad(assemblyName.FullName);
        }
        catch
        {
            // GAC 中不存在,继续尝试其他方式
        }

        // 2. 尝试从探测路径加载
        foreach (string probingPath in _probingPaths)
        {
            string assemblyFileName = $"{assemblyName.Name}.dll";
            string assemblyPath = Path.Combine(probingPath, assemblyFileName);

            if (File.Exists(assemblyPath))
            {
                try
                {
                    return Assembly.ReflectionOnlyLoadFrom(assemblyPath);
                }
                catch
                {
                    // 继续尝试其他路径
                }
            }
        }

        // 3. 尝试从当前域的基目录加载
        string baseDirectory = AppDomain.CurrentDomain.BaseDirectory;
        string baseAssemblyPath = Path.Combine(baseDirectory, $"{assemblyName.Name}.dll");

        if (File.Exists(baseAssemblyPath))
        {
            try
            {
                return Assembly.ReflectionOnlyLoadFrom(baseAssemblyPath);
            }
            catch
            {
                // 加载失败
            }
        }

        return null;
    }

    /// <summary>
    /// ReflectionOnlyAssemblyResolve 事件处理器
    /// </summary>
    private Assembly OnReflectionOnlyAssemblyResolve(object sender, ResolveEventArgs args)
    {
        // 检查是否已经加载过
        if (_loadedAssemblies.TryGetValue(args.Name, out Assembly cachedAssembly))
        {
            return cachedAssembly;
        }

        // 尝试解析程序集名称
        AssemblyName assemblyName = new AssemblyName(args.Name);

        // 尝试加载程序集
        Assembly resolvedAssembly = LoadReferencedAssembly(assemblyName);

        if (resolvedAssembly != null)
        {
            _loadedAssemblies[args.Name] = resolvedAssembly;

            // 递归加载依赖项
            try
            {
                PreloadReferencedAssemblies(resolvedAssembly);
            }
            catch
            {
                // 忽略依赖项加载错误
            }
        }

        return resolvedAssembly;
    }

    /// <summary>
    /// 释放资源
    /// </summary>
    public void Dispose()
    {
        AppDomain.CurrentDomain.ReflectionOnlyAssemblyResolve -= OnReflectionOnlyAssemblyResolve;
        _loadedAssemblies.Clear();
        _probingPaths.Clear();
    }
}
"}

