using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Reflection;
using System.Text;

/// <summary>
/// 增强版 ReflectionOnly 加载器,包含诊断和错误处理
/// </summary>
public class AdvancedReflectionOnlyLoader : IDisposable
{
    private readonly List<string> _probingPaths;
    private readonly Dictionary<string, Assembly> _loadedAssemblies;
    private readonly StringBuilder _diagnosticLog;
    private bool _enableDiagnostics;

    public AdvancedReflectionOnlyLoader(bool enableDiagnostics = false)
    {
        _probingPaths = new List<string>();
        _loadedAssemblies = new Dictionary<string, Assembly>(StringComparer.OrdinalIgnoreCase);
        _diagnosticLog = new StringBuilder();
        _enableDiagnostics = enableDiagnostics;

        AppDomain.CurrentDomain.ReflectionOnlyAssemblyResolve += OnReflectionOnlyAssemblyResolve;
    }

    /// <summary>
    /// 获取诊断日志
    /// </summary>
    public string GetDiagnosticLog()
    {
        return _diagnosticLog.ToString();
    }

    /// <summary>
    /// 添加探测路径
    /// </summary>
    public void AddProbingPath(string path)
    {
        if (string.IsNullOrWhiteSpace(path))
        {
            return;
        }

        string fullPath = Path.GetFullPath(path);

        if (Directory.Exists(fullPath) && !_probingPaths.Contains(fullPath))
        {
            _probingPaths.Add(fullPath);
            LogDiagnostic($"Added probing path: {fullPath}");
        }
        else if (!Directory.Exists(fullPath))
        {
            LogDiagnostic($"Warning: Probing path does not exist: {fullPath}");
        }
    }

    /// <summary>
    /// 自动检测并添加 Cognex VisionPro 路径
    /// </summary>
    public bool AutoDetectCognexPaths()
    {
        var potentialPaths = new[]
        {
            @"C:\Program Files\Cognex\VisionPro",
            @"C:\Program Files (x86)\Cognex\VisionPro",
            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles), "Cognex", "VisionPro"),
            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ProgramFilesX86), "Cognex", "VisionPro")
        };

        bool found = false;

        foreach (string path in potentialPaths.Distinct())
        {
            if (Directory.Exists(path))
            {
                AddProbingPath(path);
                LogDiagnostic($"Auto-detected Cognex path: {path}");
                found = true;

                // 检查是否存在 Cognex.VisionPro.dll
                string dllPath = Path.Combine(path, "Cognex.VisionPro.dll");
                if (File.Exists(dllPath))
                {
                    FileVersionInfo versionInfo = System.Diagnostics.FileVersionInfo.GetVersionInfo(dllPath);
                    LogDiagnostic($"  Found Cognex.VisionPro.dll version: {versionInfo.FileVersion}");
                }
            }
        }

        if (!found)
        {
            LogDiagnostic("Warning: Could not auto-detect Cognex VisionPro installation");
        }

        return found;
    }

    /// <summary>
    /// 预加载程序集及其所有依赖项
    /// </summary>
    public Assembly LoadAssembly(string assemblyPath)
    {
        LogDiagnostic($"\n=== Loading Assembly: {assemblyPath} ===");

        if (!File.Exists(assemblyPath))
        {
            string error = $"Assembly file not found: {assemblyPath}";
            LogDiagnostic($"ERROR: {error}");
            throw new FileNotFoundException(error, assemblyPath);
        }

        try
        {
            Assembly assembly = Assembly.ReflectionOnlyLoadFrom(assemblyPath);
            LogDiagnostic($"Successfully loaded: {assembly.FullName}");
            LogDiagnostic($"Location: {assembly.Location}");

            CacheAssembly(assembly);
            PreloadDependencies(assembly, 0);

            return assembly;
        }
        catch (Exception ex)
        {
            LogDiagnostic($"ERROR loading assembly: {ex.Message}");
            LogDiagnostic($"Stack trace: {ex.StackTrace}");
            throw;
        }
    }

    /// <summary>
    /// 递归预加载依赖项
    /// </summary>
    private void PreloadDependencies(Assembly assembly, int depth)
    {
        string indent = new string(' ', depth * 2);

        AssemblyName[] references = assembly.GetReferencedAssemblies();
        LogDiagnostic($"{indent}Referenced assemblies: {references.Length}");

        foreach (AssemblyName refName in references)
        {
            LogDiagnostic($"{indent}  - {refName.Name} (v{refName.Version})");

            if (IsAssemblyLoaded(refName.FullName))
            {
                LogDiagnostic($"{indent}    Already loaded, skipping");
                continue;
            }

            try
            {
                Assembly refAssembly = ResolveAssembly(refName, depth + 1);

                if (refAssembly != null)
                {
                    CacheAssembly(refAssembly);
                    LogDiagnostic($"{indent}    ✓ Resolved: {refAssembly.Location}");

                    // 递归加载依赖项(限制深度避免无限递归)
                    if (depth < 10)
                    {
                        PreloadDependencies(refAssembly, depth + 1);
                    }
                }
                else
                {
                    LogDiagnostic($"{indent}    ✗ Failed to resolve");
                }
            }
            catch (Exception ex)
            {
                LogDiagnostic($"{indent}    ✗ Error: {ex.Message}");
            }
        }
    }

    /// <summary>
    /// 解析程序集
    /// </summary>
    private Assembly ResolveAssembly(AssemblyName assemblyName, int depth)
    {
        string indent = new string(' ', depth * 2);

        // 1. 尝试从 GAC 加载
        LogDiagnostic($"{indent}  Trying GAC...");
        try
        {
            Assembly gacAssembly = Assembly.ReflectionOnlyLoad(assemblyName.FullName);
            LogDiagnostic($"{indent}    Found in GAC");
            return gacAssembly;
        }
        catch
        {
            LogDiagnostic($"{indent}    Not in GAC");
        }

        // 2. 尝试从探测路径加载
        LogDiagnostic($"{indent}  Searching probing paths ({_probingPaths.Count})...");
        foreach (string probingPath in _probingPaths)
        {
            string[] possibleExtensions = { ".dll", ".exe" };

            foreach (string ext in possibleExtensions)
            {
                string assemblyPath = Path.Combine(probingPath, assemblyName.Name + ext);

                if (File.Exists(assemblyPath))
                {
                    try
                    {
                        LogDiagnostic($"{indent}    Trying: {assemblyPath}");
                        Assembly loadedAssembly = Assembly.ReflectionOnlyLoadFrom(assemblyPath);

                        // 验证版本
                        if (IsVersionCompatible(assemblyName, loadedAssembly.GetName()))
                        {
                            return loadedAssembly;
                        }
                        else
                        {
                            LogDiagnostic($"{indent}    Version mismatch: requested {assemblyName.Version}, found {loadedAssembly.GetName().Version}");
                        }
                    }
                    catch (Exception ex)
                    {
                        LogDiagnostic($"{indent}    Failed: {ex.Message}");
                    }
                }
            }
        }

        // 3. 尝试从应用程序目录加载
        LogDiagnostic($"{indent}  Trying application directory...");
        string appDirPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, assemblyName.Name + ".dll");

        if (File.Exists(appDirPath))
        {
            try
            {
                return Assembly.ReflectionOnlyLoadFrom(appDirPath);
            }
            catch (Exception ex)
            {
                LogDiagnostic($"{indent}    Failed: {ex.Message}");
            }
        }

        return null;
    }

    /// <summary>
    /// 检查版本兼容性
    /// </summary>
    private bool IsVersionCompatible(AssemblyName requested, AssemblyName actual)
    {
        // 如果请求的版本为 null,接受任何版本
        if (requested.Version == null)
        {
            return true;
        }

        // 精确匹配
        if (requested.Version == actual.Version)
        {
            return true;
        }

        // 主版本和次版本匹配(允许修订号差异)
        if (requested.Version.Major == actual.Version.Major &&
            requested.Version.Minor == actual.Version.Minor)
        {
            return true;
        }

        return false;
    }

    /// <summary>
    /// ReflectionOnlyAssemblyResolve 事件处理器
    /// </summary>
    private Assembly OnReflectionOnlyAssemblyResolve(object sender, ResolveEventArgs args)
    {
        LogDiagnostic($"\n[ReflectionOnlyResolve Event]");
        LogDiagnostic($"  Requested: {args.Name}");
        LogDiagnostic($"  Requesting Assembly: {args.RequestingAssembly?.FullName ?? "(null)"}");

        // 检查缓存
        if (_loadedAssemblies.TryGetValue(args.Name, out Assembly cachedAssembly))
        {
            LogDiagnostic($"  Found in cache");
            return cachedAssembly;
        }

        // 解析程序集
        AssemblyName assemblyName = new AssemblyName(args.Name);
        Assembly resolvedAssembly = ResolveAssembly(assemblyName, 0);

        if (resolvedAssembly != null)
        {
            CacheAssembly(resolvedAssembly);
            LogDiagnostic($"  ✓ Resolved successfully");

            // 预加载其依赖项
            try
            {
                PreloadDependencies(resolvedAssembly, 1);
            }
            catch (Exception ex)
            {
                LogDiagnostic($"  Warning: Failed to preload dependencies: {ex.Message}");
            }
        }
        else
        {
            LogDiagnostic($"  ✗ Resolution failed");
        }

        return resolvedAssembly;
    }

    /// <summary>
    /// 缓存程序集
    /// </summary>
    private void CacheAssembly(Assembly assembly)
    {
        if (assembly != null && !_loadedAssemblies.ContainsKey(assembly.FullName))
        {
            _loadedAssemblies[assembly.FullName] = assembly;
        }
    }

    /// <summary>
    /// 检查程序集是否已加载
    /// </summary>
    private bool IsAssemblyLoaded(string fullName)
    {
        return _loadedAssemblies.ContainsKey(fullName);
    }

    /// <summary>
    /// 记录诊断信息
    /// </summary>
    private void LogDiagnostic(string message)
    {
        if (_enableDiagnostics)
        {
            string timestampedMessage = $"[{DateTime.Now:HH:mm:ss.fff}] {message}";
            _diagnosticLog.AppendLine(timestampedMessage);
            Console.WriteLine(timestampedMessage);
        }
    }

    /// <summary>
    /// 获取所有已加载的程序集
    /// </summary>
    public IReadOnlyDictionary<string, Assembly> GetLoadedAssemblies()
    {
        return _loadedAssemblies;
    }

    /// <summary>
    /// 打印加载摘要
    /// </summary>
    public void PrintLoadSummary()
    {
        Console.WriteLine("\n=== Load Summary ===");
        Console.WriteLine($"Total assemblies loaded: {_loadedAssemblies.Count}");
        Console.WriteLine($"Probing paths configured: {_probingPaths.Count}");

        Console.WriteLine("\nLoaded assemblies:");
        foreach (var kvp in _loadedAssemblies.OrderBy(x => x.Key))
        {
            Console.WriteLine($"  {kvp.Value.GetName().Name} (v{kvp.Value.GetName().Version})");
            Console.WriteLine($"    Location: {kvp.Value.Location}");
        }

        Console.WriteLine("\nProbing paths:");
        foreach (string path in _probingPaths)
        {
            Console.WriteLine($"  {path}");
        }
    }

    public void Dispose()
    {
        AppDomain.CurrentDomain.ReflectionOnlyAssemblyResolve -= OnReflectionOnlyAssemblyResolve;
        _loadedAssemblies.Clear();
        _probingPaths.Clear();
        _diagnosticLog.Clear();
    }
}

/// <summary>
/// 使用示例
/// </summary>
public class AdvancedLoaderExample
{
    public static void Main(string[] args)
    {
        using (var loader = new AdvancedReflectionOnlyLoader(enableDiagnostics: true))
        {
            try
            {
                // 自动检测 Cognex 路径
                bool cognexFound = loader.AutoDetectCognexPaths();

                if (!cognexFound)
                {
                    Console.WriteLine("Warning: Cognex VisionPro not found. Please add paths manually:");
                    loader.AddProbingPath(@"C:\Your\Custom\Cognex\Path");
                }

                // 添加应用程序路径
                loader.AddProbingPath(AppDomain.CurrentDomain.BaseDirectory);

                // 加载您的程序集
                string assemblyPath = @"YourAssembly.dll";
                Assembly assembly = loader.LoadAssembly(assemblyPath);

                Console.WriteLine($"\nSuccessfully loaded: {assembly.FullName}");

                // 使用反射
                Type[] types = assembly.GetTypes();
                Console.WriteLine($"Found {types.Length} types");

                // 打印摘要
                loader.PrintLoadSummary();

                // 保存诊断日志
                File.WriteAllText("load-diagnostic.log", loader.GetDiagnosticLog());
                Console.WriteLine("\nDiagnostic log saved to: load-diagnostic.log");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"\nERROR: {ex.Message}");
                Console.WriteLine($"\nDiagnostic log:\n{loader.GetDiagnosticLog()}");
            }
        }
    }
}
