// 快速修复指南：Cognex.VisionPro ReflectionOnly 加载问题
// ========================================

// 最简单的解决方案 (复制粘贴即用)
// ========================================

using System;
using System.IO;
using System.Reflection;

public class QuickFix
{
    public static void Setup()
    {
        // 在加载任何 ReflectionOnly 程序集之前调用此方法
        AppDomain.CurrentDomain.ReflectionOnlyAssemblyResolve += (sender, args) =>
        {
            // 解析请求的程序集名称
            AssemblyName name = new AssemblyName(args.Name);

            // ====================================
            // 方案 1: 针对 Cognex.VisionPro 的特定处理
            // ====================================
            if (name.Name == "Cognex.VisionPro")
            {
                // 🔧 修改这里的路径为您的 Cognex 安装路径
                string[] cognexPaths = new[]
                {
                    @"C:\Program Files\Cognex\VisionPro\Cognex.VisionPro.dll",
                    @"C:\Program Files (x86)\Cognex\VisionPro\Cognex.VisionPro.dll",
                };

                foreach (string path in cognexPaths)
                {
                    if (File.Exists(path))
                    {
                        Console.WriteLine($"Loading Cognex.VisionPro from: {path}");
                        return Assembly.ReflectionOnlyLoadFrom(path);
                    }
                }
            }

            // ====================================
            // 方案 2: 通用解析策略
            // ====================================

            // 2a. 尝试从 GAC 加载
            try
            {
                return Assembly.ReflectionOnlyLoad(args.Name);
            }
            catch { }

            // 2b. 尝试从应用程序目录加载
            string appDir = AppDomain.CurrentDomain.BaseDirectory;
            string localPath = Path.Combine(appDir, name.Name + ".dll");

            if (File.Exists(localPath))
            {
                return Assembly.ReflectionOnlyLoadFrom(localPath);
            }

            // 2c. 尝试从请求程序集的目录加载
            if (args.RequestingAssembly != null)
            {
                string requestingDir = Path.GetDirectoryName(args.RequestingAssembly.Location);
                string relativePath = Path.Combine(requestingDir, name.Name + ".dll");

                if (File.Exists(relativePath))
                {
                    return Assembly.ReflectionOnlyLoadFrom(relativePath);
                }
            }

            Console.WriteLine($"Warning: Could not resolve: {args.Name}");
            return null;
        };
    }
}

// ========================================
// 使用方式
// ========================================

public class YourProgram
{
    public static void Main()
    {
        // 步骤 1: 在程序开始时调用 Setup
        QuickFix.Setup();

        // 步骤 2: 现在可以安全地使用 ReflectionOnly 加载
        try
        {
            Assembly assembly = Assembly.ReflectionOnlyLoadFrom(@"YourAssembly.dll");
            Console.WriteLine($"Loaded: {assembly.FullName}");

            // 使用反射
            Type[] types = assembly.GetTypes();
            Console.WriteLine($"Found {types.Length} types");
