        AppDomain.CurrentDomain.AssemblyResolve += NormalResolver;
        AppDomain.CurrentDomain.ReflectionOnlyAssemblyResolve += ReflectionOnlyResolver;
    }

    private static Assembly NormalResolver(object sender, ResolveEventArgs args)
    {
        // 正常加载上下文的解析
        return ResolveAssemblyByName(args.Name, useReflectionOnly: false);
    }

    private static Assembly ReflectionOnlyResolver(object sender, ResolveEventArgs args)
    {
        // ReflectionOnly 上下文的解析
        return ResolveAssemblyByName(args.Name, useReflectionOnly: true);
    }

    private static Assembly ResolveAssemblyByName(string fullName, bool useReflectionOnly)
    {
        AssemblyName name = new AssemblyName(fullName);

        // Cognex 特定路径
        if (name.Name == "Cognex.VisionPro")
        {
            string cognexPath = FindCognexVisionPro();
            if (!string.IsNullOrEmpty(cognexPath))
            {
                return useReflectionOnly
                    ? Assembly.ReflectionOnlyLoadFrom(cognexPath)
                    : Assembly.LoadFrom(cognexPath);
            }
        }

        // 标准解析
        try
        {
            return useReflectionOnly
                ? Assembly.ReflectionOnlyLoad(fullName)
                : Assembly.Load(fullName);
        }
        catch
        {
            return null;
        }
    }

    private static string FindCognexVisionPro()
    {
        string[] searchPaths = new[]
        {
            @"C:\Program Files\Cognex\VisionPro",
            @"C:\Program Files (x86)\Cognex\VisionPro",
            Environment.GetEnvironmentVariable("COGNEX_VISIONPRO_PATH") // 支持环境变量
        };

        foreach (string basePath in searchPaths)
        {
            if (string.IsNullOrEmpty(basePath))
                continue;

            string dllPath = Path.Combine(basePath, "Cognex.VisionPro.dll");
            if (File.Exists(dllPath))
