    <!-- 上传进度展示 -->
    <div v-if="uploadingFiles.length > 0" class="upload-progress">
      <h4>上传进度</h4>
      <div
        v-for="file in uploadingFiles"
        :key="file.uid"
        class="progress-item"
      >
        <span>{{ file.name }}</span>
        <el-progress
          :percentage="file.percentage"
          :status="file.status"
        ></el-progress>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'FileUploadExample',
  data() {
    return {
      uploadUrl: '/api/upload', // 你的上传接口地址
      fileList: [],
      uploadingFiles: [], // 正在上传的文件列表
    }
  },
  methods: {
    // 文件选择改变时触发
    handleChange(file, fileList) {
      this.fileList = fileList
    },

    // 点击开始上传按钮
    submitUpload() {
      if (this.fileList.length === 0) {
        this.$message.warning('请先选择文件')
        return
      }

      // 遍历文件列表，逐个上传
      this.uploadingFiles = this.fileList.map(file => ({
        uid: file.uid,
        name: file.name,
        percentage: 0,
        status: ''
      }))

      // 逐个上传文件
      this.uploadFilesOneByOne()
    },

    // 逐个上传文件
    async uploadFilesOneByOne() {
      for (let i = 0; i < this.fileList.length; i++) {
        const file = this.fileList[i]

        // 跳过已经上传成功的文件
        if (file.status === 'success') {
          continue
        }

        try {
          await this.uploadSingleFile(file, i)
        } catch (error) {
          console.error(`文件 ${file.name} 上传失败:`, error)
          // 可以选择继续上传下一个文件，或者中断上传
          // 这里选择继续上传
          continue
        }
      }

      this.$message.success('所有文件上传完成')
    },

    // 上传单个文件
    uploadSingleFile(file, index) {
      return new Promise((resolve, reject) => {
        const formData = new FormData()
        formData.append('file', file.raw)
        // 可以添加其他参数
        // formData.append('userId', this.userId)

        // 使用 axios 或其他 HTTP 库上传
        this.$axios({
          method: 'post',
          url: this.uploadUrl,
          data: formData,
          headers: {
            'Content-Type': 'multipart/form-data'
          },
          onUploadProgress: (progressEvent) => {
            // 更新上传进度
            const percentage = Math.round(
              (progressEvent.loaded * 100) / progressEvent.total
            )
            this.updateFileProgress(file.uid, percentage)
          }
        })
          .then(response => {
            // 上传成功
            this.updateFileProgress(file.uid, 100, 'success')
            this.$message.success(`${file.name} 上传成功`)
            resolve(response)
          })
          .catch(error => {
            // 上传失败
            this.updateFileProgress(file.uid, 0, 'exception')
            this.$message.error(`${file.name} 上传失败`)
            reject(error)
          })
      })
    },

    // 更新文件上传进度
    updateFileProgress(uid, percentage, status = '') {
      const file = this.uploadingFiles.find(f => f.uid === uid)
      if (file) {
        file.percentage = percentage
        if (status) {
          file.status = status
        }
      }
    },

    // 自定义上传方法（如果设置了 :http-request）
    handleUpload(options) {
      const { file, onProgress, onSuccess, onError } = options
      const formData = new FormData()
      formData.append('file', file)

      this.$axios({
        method: 'post',
        url: this.uploadUrl,
        data: formData,
        headers: {
          'Content-Type': 'multipart/form-data'
        },
        onUploadProgress: (progressEvent) => {
          const percentage = Math.round(
            (progressEvent.loaded * 100) / progressEvent.total
          )
          onProgress({ percent: percentage })
        }
      })
        .then(response => {
          onSuccess(response.data)
        })
        .catch(error => {
          onError(error)
        })
    },

    // 上传成功回调
    handleSuccess(response, file, fileList) {
      console.log('上传成功:', response, file)
    },

    // 上传失败回调
    handleError(err, file, fileList) {
      console.error('上传失败:', err, file)
    }
  }
}
</script>

