{"file_path": "/home/ubuntu/single/workspace_simple/task_dc497cd5835c61e59db05169faeef0bb/file-upload-fetch.vue", "content": "<template>
  <div class="file-upload-fetch">
    <el-upload
      action="#"
      :http-request="handleUpload"
      :on-remove="handleRemove"
      :before-remove="beforeRemove"
      multiple
      :auto-upload="true"
      :limit="5"
      :on-exceed="handleExceed"
    >
      <el-button size="small" type="primary">选择文件</el-button>
      <div slot="tip" class="el-upload__tip">
        一次最多上传5个文件，每个文件单独调用接口上传
      </div>
    </el-upload>
  </div>
</template>

<script>
export default {
  name: 'FileUploadFetch',
  data() {
    return {
      uploadUrl: '/api/upload'
    }
  },
  methods: {
    // 使用 fetch 上传单个文件
    async handleUpload(options) {
      const { file, onProgress, onSuccess, onError } = options

      try {
        const formData = new FormData()
        formData.append('file', file)

        // 使用 XMLHttpRequest 以便监听上传进度
        const xhr = new XMLHttpRequest()

        // 监听上传进度
        xhr.upload.addEventListener('progress', (e) => {
          if (e.lengthComputable) {
            const percentage = Math.round((e.loaded * 100) / e.total)
            onProgress({ percent: percentage })
          }
        })

        // 监听上传完成
        xhr.addEventListener('load', () => {
          if (xhr.status === 200) {
            const response = JSON.parse(xhr.responseText)
            this.$message.success(`${file.name} 上传成功`)
            onSuccess(response)
          } else {
            const error = new Error(`上传失败: ${xhr.statusText}`)
            this.$message.error(`${file.name} 上传失败`)
            onError(error)
          }
        })

        // 监听上传错误
        xhr.addEventListener('error', () => {
          const error = new Error('网络错误')
          this.$message.error(`${file.name} 上传失败`)
          onError(error)
        })

        // 发送请求
        xhr.open('POST', this.uploadUrl)
        // 如果需要添加 token
        // xhr.setRequestHeader('Authorization', `Bearer ${token}`)
        xhr.send(formData)

      } catch (error) {
        console.error('上传异常:', error)
        this.$message.error(`${file.name} 上传异常`)
        onError(error)
      }
    },

    // 文件超出限制
    handleExceed(files, fileList) {
      this.$message.warning(`当前限制选择 5 个文件，本次选择了 ${files.length} 个文件，共选择了 ${files.length + fileList.length} 个文件`)
    },

    // 删除文件之前
    beforeRemove(file, fileList) {
      return this.$confirm(`确定移除 ${file.name}？`)
    },

    // 删除文件
    handleRemove(file, fileList) {
      console.log('文件已移除:', file.name)
    }
  }
}
</script>

<style scoped>
.file-upload-fetch {
  padding: 20px;
}
</style>
"}

{"file_path": "/home/ubuntu/work/single/workspace_simple/task_697236713e9b46c7362b7d92c0379b69/matlab_plot_fix.m", "content": "%% Matlab 绘图问题分析与修复示例
% 问题：绘图只显示坐标轴，没有内容

%% 常见问题 1: 数据为空或未定义
fprintf('=== 问题 1: 数据为空 ===\n');

% 错误示例
x_empty = [];
y_empty = [];
figure(1);
plot(x_empty, y_empty);
title('错误示例：空数据');
xlabel('X轴');
ylabel('Y轴');
grid on;

% 正确示例
x = 0:0.1:10;
y = sin(x);
figure(2);
plot(x, y, 'b-', 'LineWidth', 2);
title('正确示例：有效数据');
xlabel('X轴');
ylabel('Y轴');
grid on;

%% 常见问题 2: 数据范围问题（NaN 或 Inf）
fprintf('=== 问题 2: 数据包含 NaN 或 Inf ===\n');

% 错误示例
x2 = 0:0.1:10;
y2 = log(x2 - 10);  % 会产生 NaN
figure(3);
plot(x2, y2);
title('错误示例：数据包含 NaN');
xlabel('X轴');
ylabel('Y轴');
grid on;

% 正确示例：过滤无效数据
x3 = 0:0.1:10;
y3 = log(x3 + 1);  % 确保参数为正
% 或者过滤 NaN
valid_idx = ~isnan(y3) & ~isinf(y3);
figure(4);
plot(x3(valid_idx), y3(valid_idx), 'r-', 'LineWidth', 2);
title('正确示例：过滤无效数据');
xlabel('X轴');
ylabel('Y轴');
grid on;

%% 常见问题 3: 坐标轴范围设置不当
fprintf('=== 问题 3: 坐标轴范围问题 ===\n');

% 错误示例
x4 = 0:0.1:10;
y4 = sin(x4);
figure(5);
plot(x4, y4);
axis([100, 200, -10, 10]);  % 范围远离数据
title('错误示例：坐标轴范围不当');
xlabel('X轴');
ylabel('Y轴');
grid on;

% 正确示例
figure(6);
plot(x4, y4, 'g-', 'LineWidth', 2);
axis tight;  % 自动调整到数据范围
% 或者使用 xlim([0, 10]); ylim([-1.5, 1.5]);
title('正确示例：正确的坐标轴范围');
xlabel('X轴');
ylabel('Y轴');
grid on;

%% 常见问题 4: hold on 后未绘制新数据
fprintf('=== 问题 4: hold on 使用不当 ===\n');

% 错误示例
figure(7);
plot([], []);  % 先绘制空数据
hold on;
% 忘记绘制实际数据
title('错误示例：hold on 后未绘制');
xlabel('X轴');
ylabel('Y轴');
grid on;

% 正确示例
figure(8);
x5 = 0:0.1:10;
y5_1 = sin(x5);
y5_2 = cos(x5);
plot(x5, y5_1, 'b-', 'LineWidth', 2);
hold on;
plot(x5, y5_2, 'r--', 'LineWidth', 2);
hold off;
title('正确示例：正确使用 hold on');
xlabel('X轴');
ylabel('Y轴');
legend('sin(x)', 'cos(x)');
grid on;

%% 常见问题 5: 图形句柄或 clf 使用问题
fprintf('=== 问题 5: 图形被清除 ===\n');

% 错误示例
figure(9);
x6 = 0:0.1:10;
y6 = exp(-x6/5) .* sin(x6);
plot(x6, y6);
clf;  % 清除了刚绘制的内容
title('错误示例：绘图后被清除');
xlabel('X轴');
ylabel('Y轴');
grid on;

% 正确示例
figure(10);
plot(x6, y6, 'm-', 'LineWidth', 2);
title('正确示例：不清除图形');
xlabel('X轴');
ylabel('Y轴');
grid on;

%% 完整的正确绘图示例
fprintf('=== 完整的正确绘图示例 ===\n');

figure(11);
% 准备数据
t = linspace(0, 2*pi, 100);
y1 = sin(t);
y2 = cos(t);
y3 = sin(2*t);

% 绘制多条曲线
plot(t, y1, 'b-', 'LineWidth', 2, 'DisplayName', 'sin(t)');
hold on;
plot(t, y2, 'r--', 'LineWidth', 2, 'DisplayName', 'cos(t)');
plot(t, y3, 'g-.', 'LineWidth', 2, 'DisplayName', 'sin(2t)');
hold off;

% 设置图形属性
title('完整示例：三角函数对比', 'FontSize', 14, 'FontWeight', 'bold');
xlabel('时间 t (弧度)', 'FontSize', 12);
ylabel('幅值', 'FontSize', 12);
legend('Location', 'best');
grid on;
axis tight;

% 设置坐标轴范围（可选）
xlim([0, 2*pi]);
ylim([-1.2, 1.2]);

%% 调试技巧
fprintf('\n=== 调试技巧 ===\n');
fprintf('1. 检查数据：使用 disp(x), disp(y) 查看数据\n');
fprintf('2. 检查数据大小：使用 size(x), size(y)\n');
fprintf('3. 检查数据有效性：使用 any(isnan(y)), any(isinf(y))\n');
fprintf('4. 检查坐标轴：使用 axis auto 或 axis tight\n');
fprintf('5. 检查图形句柄：使用 get(gca) 查看当前坐标轴属性\n');

% 示例调试代码
x_debug = 0:0.1:10;
y_debug = sin(x_debug);

fprintf('\n数据检查：\n');
fprintf('x 大小: %d x %d\n', size(x_debug, 1), size(x_debug, 2));
fprintf('y 大小: %d x %d\n', size(y_debug, 1), size(y_debug, 2));
fprintf('y 包含 NaN: %d\n', any(isnan(y_debug)));
fprintf('y 包含 Inf: %d\n', any(isinf(y_debug)));
fprintf('y 范围: [%.2f, %.2f]\n', min(y_debug), max(y_debug));

fprintf('\n所有示例绘制完成！\n');
"}

