{"file_path": "/home/ubuntu/single/workspace_simple/task_1ec19bcd06a5d261bd3eff88c30e7064/sum_numbers.c", "content": "#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    FILE *file;
    char line[256];
    double number;
    double sum = 0.0;
    int count = 0;

    // 检查命令行参数
    if (argc != 2) {
        printf("使用方法: %s <文件名>\n", argv[0]);
        return 1;
    }

    // 打开文件
    file = fopen(argv[1], "r");
    if (file == NULL) {
        printf("错误: 无法打开文件 '%s'\n", argv[1]);
        return 1;
    }

    printf("读取文件: %s\n", argv[1]);
    printf("----------------------------------------\n");

    // 逐行读取文件
    while (fgets(line, sizeof(line), file) != NULL) {
        // 尝试将行转换为数字
        if (sscanf(line, "%lf", &number) == 1) {
            printf("读取数字: %.2f\n", number);
            sum += number;
            count++;
        }
    }

    // 关闭文件
    fclose(file);

    printf("----------------------------------------\n");
    printf("共读取 %d 个数字\n", count);
    printf("累加和: %.2f\n", sum);

    return 0;
}
"}

{"file_path": "/home/ubuntu/work/single/workspace_simple/task_fefbbb95e5c6100808695c8841a88719/nginx-google-proxy.conf", "content": "server {
    listen 8080;
    server_name localhost;

    # 设置代理超时时间
    proxy_connect_timeout 10s;
    proxy_send_timeout 60s;
    proxy_read_timeout 60s;

    # 禁用缓存
    proxy_buffering off;

    # 代理 Google 搜索
    location / {
        # 设置上游代理
        proxy_pass https://www.google.com;

        # 通过本地 HTTP 代理转发请求
        proxy_set_header Host www.google.com;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # 关键：设置 HTTP 代理
        proxy_http_version 1.1;
        proxy_set_header Connection "";

        # SSL 相关设置
        proxy_ssl_server_name on;
        proxy_ssl_protocols TLSv1.2 TLSv1.3;
    }

    # 错误页面
    error_page 500 502 503 504 /50x.html;
    location = /50x.html {
        root /usr/share/nginx/html;
    }
}

# 注意：Nginx 的 proxy_pass 不直接支持 HTTP CONNECT 代理
# 需要使用 ngx_http_proxy_connect_module 模块或其他方案
"}

{"file_path": "/home/ubuntu/work/single/workspace_simple/task_fefbbb95e5c6100808695c8841a88719/nginx-proxy-connect.conf", "content": "# Nginx 配置 - 需要 ngx_http_proxy_connect_module 模块支持
# 编译方法：
# 1. 下载 Nginx 源码
# 2. 下载 ngx_http_proxy_connect_module: https://github.com/chobits/ngx_http_proxy_connect_module
# 3. 编译: ./configure --add-module=/path/to/ngx_http_proxy_connect_module && make && make install

server {
    listen 8080;
    server_name localhost;

    # 启用 CONNECT 方法支持
    proxy_connect;
    proxy_connect_allow 443 563;
    proxy_connect_connect_timeout 10s;
    proxy_connect_read_timeout 10s;
    proxy_connect_send_timeout 10s;

    location / {
        # 设置上游 HTTP 代理
        proxy_pass http://127.0.0.1:7890;

        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # 支持 WebSocket
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
    }
}
"}
